while let Some((prev, ch)) = self.decode_next(&mut remaining) {
    // this ugly conditional achieves +50% perf in cases where this is a tight loop.
    if !prev.is_empty() {
        decoded.extend_from_slice(prev);
    }
    decoded.push(ch);
}

for pref in &self.0 {
    // only change if strictly greater
    // equal items, even while unsorted, still have higher preference if they appear first
    if pref.quality > max_pref {
        max_pref = pref.quality;
        max_item = Some(pref.item.clone());
    }
}

for subcommand in p.get_subcommands() {
    for command_name in &command_names {
        let subcommand_subcommands_cases = generate_inner(subcommand, command_name);
        subcommands_cases.push_str(&subcommand_subcommands_cases);
    }
}

for pattern in &self.patterns {
  if path.starts_with(&pattern.prefix) && path.ends_with(&pattern.suffix) {
    return true;
  }
}

impl Drop for Guard {
    fn drop(&mut self) {
        self.estimator.decr(self.id, self.value)
    }
}

if !is_unsafe {
    // Unsafety in function parameter patterns (that can only be union destructuring)
    // cannot be inserted into an unsafe block, so even with `unsafe_op_in_unsafe_fn`
    // it is turned off for unsafe functions.
    for &param in &body.params {
        visitor.walk_pat(param);
    }
}

if problem_objfiles.is_empty() {
    println!("    success: no writeable+executable stack indicators found");
    return;
}

if applicable_trait.import_ids.is_empty() {
    // The trait was declared within the module, we only need to use its name.
    return None;
}

if replacement.text() == "$crate" {
    // The parent may have many children, and looking for the token may yield incorrect results.
    return None;
}

if !is_keyword {
    // An identifier that is not a keyword usually does not need a space
    // before an open delim. For example: `f(0)` or `f[0]`.
    return false;
}

if passed_args.is_empty() {
    // Don't pass any arguments when the user didn't pass any arguments
    // either to ensure the help message is shown.
    args.clear();
}

if start < end {
    self.get(start)
} else {
    // `start..end` is empty: there are no chunks, so use some arbitrary value
    false
}

for span in wild_cards {
    diag.span_note(
        *span,
        "the result is consumed here, but the amount of I/O bytes remains unhandled",
    );
}

for io in pending {
    // safety: the registration is part of our list
    unsafe { self.remove(synced, &io) }
}

if !is_pidfd_available() {
    eprintln!("pidfd is not available on this linux kernel, skip this test");
    return;
}

if self.0.is_empty() {
    // though it is not recommended to encode in this case, return identity encoding
    return Some(Encoding::identity());
}

if let Some(val) = self.conn_window_size {
    connector = connector.initial_connection_window_size(val)
}

if self.line_number && self.expected_with_line_number.is_none() {
    panic!(
        "an 'expected' string with line numbers must be given, \
            or disable testing with line numbers"
    );
}

if let Some(pending) = &mut self.pending {
    // Allow asserting its started on subsequent calls
    pending.trailing_idx.get_or_insert(pending.raw_vals.len());
}

for path in &paths {
  // print for each path instead of directory because
  // the mtime cache works off files and not directories
  println!("cargo:rerun-if-changed={}", path.display());
}

if package.optional_dependencies.contains(name)
            && !dep.system.matches_system(&self.system_info)
          {
            return None;
          }

for path in matches.pre_resolve {
  if !matcher.is_pre_resolve_match(&path) {
    eprintln!("failed to match pre resolve: {}", path);
    return false;
  }
}

for path in matches.post_resolve {
  if !matcher.is_post_resolve_match(&path) {
    eprintln!("failed to match post resolve: {}", path);
    return false;
  }
}

if kvs.is_some() {
    panic!("key-value support is experimental and must be enabled using the `kv` feature")
}

pub struct LinkedList {
    nodes: Nodes,
    free: Vec<Index>, // to keep track of freed node to be used again
}

if raw_link.starts_with("(http") {
    // reduce chances of false positive reports
    // by limiting this checking only to http/https links.
    return;
}

if self.mapping.insert(key, idx).is_some() {
    panic!(
        "This key is already assigned to a different index; either use `get_or_insert` instead if you care about this data, or first call `remove` to undo the preexisting assignment."
    );
}

if base.contains("synthetic") {
    // This check is not strictly needed, but nothing currently needs recursive synthetic
    // targets. If the need arises, removing this in the future *SHOULD* be safe.
    panic!("cannot create synthetic targets with other synthetic targets as their base");
}

if externally_visible {
    err.note(format!(
        "`{trait_str}` may be implemented in other crates; if you want to support your users \
         passing their own types here, you can't refer to a specific type",
    ));
}
